public class Solution {
    public String shiftingLetters(String s, int[] shifts) {
        int n = s.length();
        for (int i = n - 2; i >= 0; i--) {
            shifts[i] = (shifts[i] + shifts[i + 1]) % 26;
        }

        char[] result = new char[n];
        for (int i = 0; i < n; i++) {
            result[i] = (char)(((s.charAt(i) - 'a') + shifts[i]) % 26 + 'a');
        }

        return new String(result);
    }
}
